import { vi } from 'vitest';
import { formatCrmProperties } from "../../utils/formatCrmProperties.js";
const mockFormatCrmProperties = vi.fn();
Object.defineProperty(global, 'self', {
    value: {
        __HUBSPOT_EXTENSION_WORKER__: true,
        hsWorkerAPI: {
            formatCrmProperties: mockFormatCrmProperties,
        },
    },
    writable: true,
});
const makeResponse = (data) => ({
    ok: true,
    json: vi.fn().mockResolvedValue(data),
});
describe('formatCrmProperties', () => {
    beforeEach(() => {
        vi.clearAllMocks();
    });
    describe('single-item input', () => {
        it('returns a single map when called with a single properties map', async () => {
            const formatted = { firstname: 'John', createdate: 'January 1, 2024' };
            mockFormatCrmProperties.mockResolvedValue(makeResponse([formatted]));
            const result = await formatCrmProperties({
                properties: { firstname: 'john', createdate: '1704067200000' },
                objectType: '0-1',
            });
            expect(result).toEqual(formatted);
        });
        it('passes a propertiesList with one item to the worker API', async () => {
            const input = { firstname: 'john' };
            mockFormatCrmProperties.mockResolvedValue(makeResponse([{ firstname: 'John' }]));
            await formatCrmProperties({ properties: input, objectType: '0-1' });
            expect(mockFormatCrmProperties).toHaveBeenCalledOnce();
            const [request] = mockFormatCrmProperties.mock.calls[0];
            expect(request.propertiesList).toEqual([input]);
            expect(request.objectType).toBe('0-1');
        });
        it('forwards formattingOptions to the worker API', async () => {
            const formattingOptions = { currency: { addSymbol: true } };
            mockFormatCrmProperties.mockResolvedValue(makeResponse([{ amount: '$100' }]));
            await formatCrmProperties({
                properties: { amount: '100' },
                objectType: '0-2',
                formattingOptions,
            });
            const [request] = mockFormatCrmProperties.mock.calls[0];
            expect(request.formattingOptions).toEqual(formattingOptions);
        });
        it('handles null property values in the input', async () => {
            const input = { firstname: null, email: 'john@example.com' };
            const formatted = { firstname: null, email: 'john@example.com' };
            mockFormatCrmProperties.mockResolvedValue(makeResponse([formatted]));
            const result = await formatCrmProperties({
                properties: input,
                objectType: '0-1',
            });
            expect(result).toEqual(formatted);
        });
    });
    describe('array input', () => {
        it('returns an array when called with an array of properties maps', async () => {
            const formatted = [{ firstname: 'John' }, { firstname: 'Jane' }];
            mockFormatCrmProperties.mockResolvedValue(makeResponse(formatted));
            const result = await formatCrmProperties({
                properties: [{ firstname: 'john' }, { firstname: 'jane' }],
                objectType: '0-1',
            });
            expect(result).toEqual(formatted);
        });
        it('passes the full array as propertiesList to the worker API', async () => {
            const input = [{ firstname: 'john' }, { firstname: 'jane' }];
            mockFormatCrmProperties.mockResolvedValue(makeResponse([{ firstname: 'John' }, { firstname: 'Jane' }]));
            await formatCrmProperties({ properties: input, objectType: '0-1' });
            const [request] = mockFormatCrmProperties.mock.calls[0];
            expect(request.propertiesList).toEqual(input);
        });
        it('preserves result order from the worker API', async () => {
            const formatted = [{ id: 'first' }, { id: 'second' }, { id: 'third' }];
            mockFormatCrmProperties.mockResolvedValue(makeResponse(formatted));
            const result = await formatCrmProperties({
                properties: [{ id: '1' }, { id: '2' }, { id: '3' }],
                objectType: '0-1',
            });
            expect(result).toEqual(formatted);
        });
        it('returns an empty array when given an empty array', async () => {
            mockFormatCrmProperties.mockResolvedValue(makeResponse([]));
            const result = await formatCrmProperties({
                properties: [],
                objectType: '0-1',
            });
            expect(result).toEqual([]);
        });
    });
    describe('error handling', () => {
        it('propagates rejections from the worker API', async () => {
            mockFormatCrmProperties.mockRejectedValue(new Error('Worker error'));
            await expect(formatCrmProperties({
                properties: { firstname: 'John' },
                objectType: '0-1',
            })).rejects.toThrow('Worker error');
        });
    });
});
